using System.ComponentModel.DataAnnotations;

namespace sv_a9ba8883ad544e9789f4734db7fee34c.Services;

public class ReviewSubmissionModel
{
    [Required(ErrorMessage = "Product name is required.")]
    public string ProductName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Rating is required.")]
    [Range(1, 5, ErrorMessage = "Rating must be between 1 and 5.")]
    public int? Rating { get; set; }

    [Required(ErrorMessage = "Review title is required.")]
    [MaxLength(100, ErrorMessage = "Review title must be 100 characters or fewer.")]
    public string ReviewTitle { get; set; } = string.Empty;

    [Required(ErrorMessage = "Review body is required.")]
    [MaxLength(2000, ErrorMessage = "Review body must be 2000 characters or fewer.")]
    public string ReviewBody { get; set; } = string.Empty;
}

public class ReviewValidationResult
{
    public bool Success { get; set; }
    public Dictionary<string, string> FieldErrors { get; set; } = new();
}

public class ReviewService
{
    public Task<ReviewValidationResult> ValidateAndSubmitAsync(ReviewSubmissionModel model, List<(string FileName, long Size)> photos)
    {
        var result = new ReviewValidationResult();

        // Simulate server-side profanity check
        if (model.ReviewTitle.Contains("spam", StringComparison.OrdinalIgnoreCase))
        {
            result.FieldErrors[nameof(model.ReviewTitle)] = "Review title contains inappropriate language.";
        }

        result.Success = result.FieldErrors.Count == 0;
        return Task.FromResult(result);
    }
}

@page "/write-review"
@rendermode InteractiveServer
@using sv_a9ba8883ad544e9789f4734db7fee34c.Services
@inject ReviewService ReviewService

<PageTitle>Write a Review</PageTitle>

<h1>Write a Review</h1>

@if (submitted)
{
    <div class="alert alert-success" role="alert">
        <h4>Thank you!</h4>
        <p>Your review has been submitted successfully.</p>
    </div>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="write-review">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label for="productName" class="form-label">Product Name</label>
            <InputText id="productName" class="form-control" @bind-Value="model.ProductName" />
            <ValidationMessage For="() => model.ProductName" />
            @if (serverErrors.ContainsKey(nameof(model.ProductName)))
            {
                <div class="validation-message">@serverErrors[nameof(model.ProductName)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="rating" class="form-label">Rating</label>
            <InputNumber id="rating" class="form-control" @bind-Value="model.Rating" />
            <ValidationMessage For="() => model.Rating" />
            @if (serverErrors.ContainsKey(nameof(model.Rating)))
            {
                <div class="validation-message">@serverErrors[nameof(model.Rating)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="reviewTitle" class="form-label">Review Title</label>
            <InputText id="reviewTitle" class="form-control" @bind-Value="model.ReviewTitle" />
            <ValidationMessage For="() => model.ReviewTitle" />
            @if (serverErrors.ContainsKey(nameof(model.ReviewTitle)))
            {
                <div class="validation-message">@serverErrors[nameof(model.ReviewTitle)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="reviewBody" class="form-label">Review Body</label>
            <InputTextArea id="reviewBody" class="form-control" rows="5" @bind-Value="model.ReviewBody" />
            <ValidationMessage For="() => model.ReviewBody" />
            @if (serverErrors.ContainsKey(nameof(model.ReviewBody)))
            {
                <div class="validation-message">@serverErrors[nameof(model.ReviewBody)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="photos" class="form-label">Upload Photos (up to 3, JPG/PNG, max 5 MB each)</label>
            <InputFile id="photos" class="form-control" OnChange="OnPhotosSelected" multiple accept=".jpg,.jpeg,.png" />
            @if (photoError is not null)
            {
                <div class="validation-message">@photoError</div>
            }
            @if (selectedPhotos.Count > 0)
            {
                <ul class="list-unstyled mt-2">
                    @foreach (var photo in selectedPhotos)
                    {
                        <li><strong>@photo.Name</strong> — @FormatSize(photo.Size)</li>
                    }
                </ul>
            }
        </div>

        <button type="submit" class="btn btn-primary" disabled="@isSubmitting">
            @if (isSubmitting)
            {
                <span class="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
                <span>Submitting…</span>
            }
            else
            {
                <span>Submit Review</span>
            }
        </button>
    </EditForm>
}

@code {
    private ReviewSubmissionModel model = new();
    private List<IBrowserFile> selectedPhotos = new();
    private Dictionary<string, string> serverErrors = new();
    private string? photoError;
    private bool submitted;
    private bool isSubmitting;

    private const long MaxFileSize = 5 * 1024 * 1024; // 5 MB
    private const int MaxFiles = 3;
    private static readonly string[] AllowedExtensions = { ".jpg", ".jpeg", ".png" };

    private void OnPhotosSelected(InputFileChangeEventArgs e)
    {
        photoError = null;
        var files = e.GetMultipleFiles(MaxFiles + 1);

        if (files.Count > MaxFiles)
        {
            photoError = $"You can upload a maximum of {MaxFiles} photos.";
            return;
        }

        foreach (var file in files)
        {
            var ext = Path.GetExtension(file.Name).ToLowerInvariant();
            if (!AllowedExtensions.Contains(ext))
            {
                photoError = $"File \"{file.Name}\" is not a supported format. Only JPG and PNG are allowed.";
                return;
            }
            if (file.Size > MaxFileSize)
            {
                photoError = $"File \"{file.Name}\" exceeds the 5 MB size limit.";
                return;
            }
        }

        selectedPhotos = files.ToList();
    }

    private async Task HandleSubmit()
    {
        serverErrors.Clear();
        isSubmitting = true;

        try
        {
            var photoMetadata = selectedPhotos
                .Select(f => (f.Name, f.Size))
                .ToList();

            var result = await ReviewService.ValidateAndSubmitAsync(model, photoMetadata);

            if (!result.Success)
            {
                serverErrors = result.FieldErrors;
            }
            else
            {
                submitted = true;
            }
        }
        finally
        {
            isSubmitting = false;
        }
    }

    private static string FormatSize(long bytes)
    {
        if (bytes < 1024) return $"{bytes} B";
        if (bytes < 1024 * 1024) return $"{bytes / 1024.0:F1} KB";
        return $"{bytes / (1024.0 * 1024.0):F2} MB";
    }
}

